 19	/**
 20	 * The generic form action skeleton (ADR 0007; registration-launch Branch 6.2).
 21	 * Collapses the `parse → decode → notify → toast.redirect` pipeline triplicated
 22	 * verbatim across `contact.tsx`, `volunteer.tsx`, and the registration route into
 23	 * ONE parameterized effect, driven by the form's `FormDefinition` (read through
 24	 * Branch 5's `Content.getForm`). Branches 6.3–6.5 migrate the three actions onto
 25	 * it behind the equivalence harness; this sub-commit lands the skeleton + tests.
 26	 *
 27	 * The triplicated body each route writes today (`contact.tsx:139-179`):
 28	 *   1. read the parsed `SubmissionContext`;
 29	 *   2. `parseSchema(handTunedSchema, payload)` → on failure
 30	 *      `formValidationError(formatSchemaResult(...))`;
 31	 *   3. build + `mailer.send` a notification, mapping a send failure to a
 32	 *      form-level error key;
 33	 *   4. `toast.redirect` to the same path with a success toast.
 34	 *
 35	 * The skeleton reproduces steps 1, 2, and 4 exactly; step 3 (the notification) is
 36	 * the only form-specific part, so it is the caller's `notify` callback. The
 37	 * notification stays a CALLBACK rather than baked in because the decoded payload's
 38	 * shape differs per form (contact's `name`/`method`, volunteer's positions list,
 39	 * registration's registrant array) and Branch 7 splits notification from a
 40	 * durable `Submissions.persist` write — keeping `notify` separable here is what
 41	 * lets Branch 7 add `persist` before it without rewriting this skeleton
 42	 * (`subtract-before-you-add`, the persist/notify split the Submission plan
 43	 * demands).
 44	 *
 45	 * `derive-dont-sync`: the validation comes from the stored `FormDefinition` via
 46	 * `decodeForm`, never a re-declared schema — editing `forms/<form>.json` changes
 47	 * what the action accepts with no code change (ADR 0007 consequence).
 48	 */
 49	
 50	/** The success toast copy a form shows after a valid submission. */
 51	export interface SuccessToast {
 52	  readonly title: TranslationKey;
 53	  readonly description: TranslationKey;
 54	}
 55	
 56	/**
 57	 * Configure the generic form action for one form. `form` is the `FormId` whose
 58	 * `FormDefinition` drives decode (and names the toast's `form` slot); `notify`
 59	 * runs the form-specific notification over the decoded payload and fails (with any
 60	 * `AppError`, e.g. a mailer failure mapped to a form-level key) to abort the
 61	 * redirect; `success` is the post-submit toast copy.
 62	 *
 63	 * `notify`'s context is the form-notification slice of the request runtime
 64	 * (`makeRequestRuntime`): `Mailer` (every form notifies by mail today), plus
 65	 * `ReactRouterContext` / `Content` for a notifier that needs the request or
 66	 * page/form copy. Branch 7 widens the terminal step to `persist`-then-`notify`
 67	 * over a durable `Submissions` write; keeping `notify` a caller callback (not a
 68	 * baked-in mailer) is what lets that land without rewriting this skeleton.
 69	 */
 70	export interface FormActionConfig<E> {
 71	  readonly form: FormId;
 72	  readonly notify: (
 73	    decoded: DecodedForm,
 74	  ) => Effect.Effect<
 75	    void,
 76	    E,
 77	    ReactRouterContext | Content.Service | Mailer.Service
 78	  >;
 79	  readonly success: SuccessToast;
 80	}
 81	
 82	/**
 83	 * Build the route `action` for one form. Wraps the generic body in
 84	 * `routeFormAction` (the same wrapper the hand-tuned forms use), so a migrated
 85	 * route is `export const action = formAction({ form, notify, success })` — no
 86	 * inline pipeline. The body yields a {@link FormSuccess} only to satisfy the
 87	 * wrapper's body type; on the happy path the terminal `toast.redirect` fails with
 88	 * a `RedirectError` the wrapper forwards to the runtime, so the return is
 89	 * unreachable on success.
 90	 *
 91	 * Pipeline:
 92	 *   1. `Content.getForm(form)` → the form's `FormDefinition`;
 93	 *   2. `decodeForm(definition, submission.payload)` → on failure,
 94	 *      `formValidationError(formatSchemaResult(...))` (bucketed field/form errors);
 95	 *   3. `notify(decoded)` — the caller's form-specific notification;
 96	 *   4. `toast.redirect(pathname, { success copy, form })`.
 97	 */
 98	export const formAction = <E>(config: FormActionConfig<E>) =>
 99	  routeFormAction(function* () {
100	    const { url } = yield* ReactRouterContext;
101	    const submission = yield* SubmissionContext;
102	    const content = yield* Content.Service;
103	    const toast = yield* Toast;
104	
105	    const definition = yield* content.getForm(config.form);
106	
107	    const decoded = decodeForm(definition, submission.payload);
108	    if (Result.isFailure(decoded)) {
109	      return yield* formValidationError(formatSchemaResult(decoded) ?? {});
110	    }
111	
112	    yield* config.notify(decoded.success);
113	
114	    yield* toast.redirect(url.pathname, {
115	      title: config.success.title,
116	      description: config.success.description,
117	      type: 'success',
118	      form: config.form,
119	    });
120	    return { reset: true } satisfies FormSuccess;
121	  });

